<template>
  <div>
    <div class="container" @mousemove="updateMousePosition">
      <img 
        :style="{ left: `${mouseX}px`, top: `${mouseY}px` }" 
        class="mouse-image" 
        src="../assets/circulo_borroso.png" 
        alt="Imagen"
      />
      <h1>Hola</h1>
    </div>

   
  </div>
</template>

<script>
export default {
  data() {
    return {
      mouseX: 0, 
      mouseY: 0
    };
  },
  methods: {
    updateMousePosition(event) {
      this.mouseX = event.pageX;
      this.mouseY = event.pageY;
    },
  },
};



</script>

<style scoped>
.container {
  width: 100vw;
  height: 100vh;
  overflow: hidden;
  position: relative;
  margin: 0;
  padding: 0;
}

.mouse-image {
  position: absolute;
  pointer-events: none; 
  width: 50px; 
  height: 50px;
  transform: translate(-50%, -50%); 
}




</style>




